let currentIndex = 0;

function renderNovelPage(index) {
    const step = storySteps[index];
    const visualEl = document.getElementById('novel-visual');
    const imgEl = document.getElementById('avatar');
    const textEl = document.getElementById('chat-text');
    const labelEl = document.getElementById('novel-label');
    const counterEl = document.getElementById('novel-counter');
    const prevBtn = document.getElementById('novel-prev');
    const nextBtn = document.getElementById('novel-next');

    visualEl.style.opacity = '0';
    textEl.style.opacity = '0';

    setTimeout(() => {
        imgEl.src = step.image;
        visualEl.className = step.cutout ? 'novel-cutout' : 'novel-image';
        textEl.textContent = step.text;
        labelEl.textContent = step.label || '';
        counterEl.textContent = `${index + 1} / ${storySteps.length}`;
        prevBtn.style.opacity = index === 0 ? '0.2' : '1';
        prevBtn.style.pointerEvents = index === 0 ? 'none' : 'auto';
        nextBtn.style.opacity = index === storySteps.length - 1 ? '0.2' : '1';
        nextBtn.style.pointerEvents = index === storySteps.length - 1 ? 'none' : 'auto';
        visualEl.style.opacity = '1';
        textEl.style.opacity = '1';
    }, 280);
}

function prevPage() {
    if (currentIndex > 0) {
        currentIndex--;
        renderNovelPage(currentIndex);
    }
}

function nextPage() {
    if (currentIndex < storySteps.length - 1) {
        currentIndex++;
        renderNovelPage(currentIndex);
    }
}
